import numpy as np


def inverted_dropout(x, p, mask):
    """Forward pass of inverted dropout."""
    x = np.asarray(x, dtype=float)
    if p == 0:
        return x.copy()
    mask = np.asarray(mask, dtype=float)
    return x * mask / (1.0 - p)


def l2_penalty(weights, lambda_reg):
    """L2 regularization penalty: (lambda_reg / 2) * sum(w^2)."""
    weights = np.asarray(weights, dtype=float)
    return float(lambda_reg * 0.5 * np.sum(weights ** 2))


def l2_gradient(weights, lambda_reg):
    """Gradient of the L2 term w.r.t. weights: lambda_reg * w."""
    weights = np.asarray(weights, dtype=float)
    return lambda_reg * weights


def batch_norm(batch, gamma, beta, eps=1e-5):
    """Batch normalization over a (B, D) batch along axis=0."""
    batch = np.asarray(batch, dtype=float)
    gamma = np.asarray(gamma, dtype=float)
    beta = np.asarray(beta, dtype=float)
    mean = batch.mean(axis=0, keepdims=True)
    var = batch.var(axis=0, keepdims=True)
    x_hat = (batch - mean) / np.sqrt(var + eps)
    return gamma * x_hat + beta


def layer_norm(x, gamma, beta, eps=1e-5):
    """Layer normalization over a single 1D sample."""
    x = np.asarray(x, dtype=float)
    gamma = np.asarray(gamma, dtype=float)
    beta = np.asarray(beta, dtype=float)
    mean = x.mean()
    var = x.var()
    x_hat = (x - mean) / np.sqrt(var + eps)
    return gamma * x_hat + beta


def rms_norm(x, gamma, eps=1e-6):
    """RMSNorm: LayerNorm without the mean subtraction."""
    x = np.asarray(x, dtype=float)
    gamma = np.asarray(gamma, dtype=float)
    rms = np.sqrt(np.mean(x ** 2) + eps)
    return gamma * x / rms
